144	// stablePageBounds computes the [startIdx, endIdx) slice window using stable
145	// ID-based cursors. ids must contain the stable key for each edge in order.
146	func stablePageBounds(ids []string, after, before *string) (startIdx, endIdx int) {
147		startIdx = 0
148		endIdx = len(ids)
149		if after != nil {
150			if afterID, ok := decodeStableCursor(*after); ok {
151				for i, id := range ids {
152					if id == afterID {
153						startIdx = i + 1
154						break
155					}
156				}
157			}
158		}
159		if before != nil {
160			if beforeID, ok := decodeStableCursor(*before); ok {
161				for i, id := range ids {
162					if id == beforeID {
163						endIdx = i
164						break
165					}
166				}
167			}
168		}
169		if startIdx > endIdx {
170			startIdx = endIdx
171		}
172		return startIdx, endIdx
173	}
