175	func workerConnectionFrom(workers []*Worker, first *int, after *string, last *int, before *string) *WorkerConnection {
176		all := make([]*WorkerEdge, len(workers))
177		ids := make([]string, len(workers))
178		for i, w := range workers {
179			all[i] = &WorkerEdge{Node: w, Cursor: encodeStableCursor(w.ID)}
180			ids[i] = w.ID
181		}
182		startIdx, endIdx := stablePageBounds(ids, after, before)
183		slice := all[startIdx:endIdx]
184		truncByFirst, truncByLast := false, false
185		if first != nil && *first >= 0 && *first < len(slice) {
186			slice = slice[:*first]
187			truncByFirst = true
188		}
189		if last != nil && *last >= 0 && *last < len(slice) {
190			slice = slice[len(slice)-*last:]
191			truncByLast = true
192		}
193		pageInfo := &PageInfo{
194			HasPreviousPage: startIdx > 0 || truncByLast,
195			HasNextPage:     endIdx < len(all) || truncByFirst,
196		}
197		if len(slice) > 0 {
198			pageInfo.StartCursor = &slice[0].Cursor
199			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
200		}
201		return &WorkerConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
202	}
