 50		Restart      WorkerRestartPolicy `json:"restart"`
 51		UpdatedAt    time.Time           `json:"updated_at"`
 52	}
 53	
 54	// Validate checks the desired-state invariants. It returns an error for values
 55	// that would make reconcile unsafe; it does not mutate the receiver.
 56	func (s *WorkerDesiredState) Validate() error {
 57		if s == nil {
 58			return fmt.Errorf("worker desired state is nil")
 59		}
 60		if s.Version != WorkerDesiredStateVersion {
 61			return fmt.Errorf("unsupported worker desired-state version %d (want %d)", s.Version, WorkerDesiredStateVersion)
 62		}
 63		if s.DesiredCount < 0 {
 64			return fmt.Errorf("desired_count must be >= 0, got %d", s.DesiredCount)
 65		}
 66		if s.Restart.MaxRestartsPerHour < 0 {
 67			return fmt.Errorf("restart.max_restarts_per_hour must be >= 0, got %d", s.Restart.MaxRestartsPerHour)
 68		}
 69		if s.DefaultSpec.IdleInterval != "" {
 70			if _, err := time.ParseDuration(s.DefaultSpec.IdleInterval); err != nil {
 71				return fmt.Errorf("default_spec.idle_interval %q is not a valid duration: %w", s.DefaultSpec.IdleInterval, err)
 72			}
 73		}
 74		if s.Restart.Backoff != "" {
 75			if _, err := time.ParseDuration(s.Restart.Backoff); err != nil {
 76				return fmt.Errorf("restart.backoff %q is not a valid duration: %w", s.Restart.Backoff, err)
 77			}
 78		}
 79		if s.Restart.BackoffMax != "" {
 80			if _, err := time.ParseDuration(s.Restart.BackoffMax); err != nil {
 81				return fmt.Errorf("restart.backoff_max %q is not a valid duration: %w", s.Restart.BackoffMax, err)
 82			}
 83		}
 84		return nil
 85	}
 86	
 87	// workerDesiredStatePath returns the on-disk location of the desired-state
 88	// file for projectRoot.
 89	func workerDesiredStatePath(projectRoot string) string {
 90		return ddxroot.JoinProject(projectRoot, "workers", "desired.json")
 91	}
 92	
 93	// LoadWorkerDesiredState reads .ddx/workers/desired.json for projectRoot. The
 94	// returned error wraps os.ErrNotExist when the file is absent so callers can
 95	// treat "no desired state" as "manage nothing" via errors.Is.
 96	func LoadWorkerDesiredState(projectRoot string) (*WorkerDesiredState, error) {
 97		path := workerDesiredStatePath(projectRoot)
 98		data, err := os.ReadFile(path)
 99		if err != nil {
100			return nil, err
101		}
102		var state WorkerDesiredState
103		if err := json.Unmarshal(data, &state); err != nil {
104			return nil, fmt.Errorf("parse %s: %w", path, err)
105		}
106		if err := state.Validate(); err != nil {
107			return nil, fmt.Errorf("validate %s: %w", path, err)
108		}
109		return &state, nil
110	}
111	
112	// SaveWorkerDesiredState validates and atomically persists state to
113	// .ddx/workers/desired.json. It stamps UpdatedAt and Version, and fills
114	// ProjectRoot when empty, before writing.
115	func SaveWorkerDesiredState(projectRoot string, state *WorkerDesiredState) error {
116		if state == nil {
117			return fmt.Errorf("worker desired state is nil")
118		}
119		if state.Version == 0 {
120			state.Version = WorkerDesiredStateVersion
121		}
122		if state.ProjectRoot == "" {
123			state.ProjectRoot = projectRoot
124		}
125		state.UpdatedAt = time.Now().UTC()
126		if err := state.Validate(); err != nil {
127			return err
128		}
129		path := workerDesiredStatePath(projectRoot)
130		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
131			return err
132		}
133		data, err := json.MarshalIndent(state, "", "  ")
134		if err != nil {
135			return err
136		}
137		tmp := path + ".tmp"
138		if err := os.WriteFile(tmp, append(data, '\n'), 0o644); err != nil {
139			return err
140		}
141		return os.Rename(tmp, path)
142	}

