 20	// isTerminalWorkerState reports whether a worker state is a final resting state
 21	// (the worker is no longer doing work). "stopping" is excluded — it is a
 22	// transient state on the way to "stopped".
 23	func isTerminalWorkerState(state string) bool {
 24		switch state {
 25		case "exited", "failed", "reaped", workerStateStopped:
 26			return true
 27		}
 28		return false
