 64	// WorkerSupervisor keeps the number of running server-managed workers for a
 65	// project equal to the desired_count persisted in .ddx/workers/desired.json.
 66	// It starts missing workers, stops excess workers, marks stale disk records
 67	// stopped, and restarts unexpectedly-exited workers subject to the restart
 68	// policy.
 69	type WorkerSupervisor struct {
 70		projectRoot string
 71		ctrl        workerController
 72	
 73		// RestartPauseCheck, when non-nil, gates restarts on an external blocker
 74		// such as a dirty project root or an operator-attention state. When it
 75		// returns paused=true the restart pass is skipped with the given reason.
 76		RestartPauseCheck func() (paused bool, reason string)
 77	
 78		// clock is overridable in tests; nil uses time.Now().UTC().
 79		clock func() time.Time
 80	
 81		mu sync.Mutex
 82		// managed holds the workers this supervisor started in this process.
 83		managed map[string]managedWorker
 84		// pendingRestart counts crashed managed workers awaiting restart. It
 85		// survives between reconcile passes so a restart held back by backoff or
 86		// max-restarts is retried later instead of falling through to
 87		// unconditional initial provisioning.
 88		pendingRestart int
 89		// restarts records restart timestamps for max_restarts_per_hour accounting.
 90		restarts []time.Time
 91		// backoffUntil is the earliest time the next restart may occur.
 92		backoffUntil time.Time
