111	// loadDesired reads the desired-state file, treating an absent file as
112	// "manage nothing" (desired_count 0).
113	func (s *WorkerSupervisor) loadDesired() (*WorkerDesiredState, error) {
114		state, err := LoadWorkerDesiredState(s.projectRoot)
115		if err != nil {
116			if errors.Is(err, os.ErrNotExist) {
117				return &WorkerDesiredState{Version: WorkerDesiredStateVersion}, nil
118			}
119			return nil, err
120		}
121		return state, nil
