124	// Reconcile brings the actual set of server-managed workers in line with the
125	// persisted desired state: it marks stale disk records stopped, restarts
126	// crashed managed workers (policy permitting), starts missing workers, and
127	// stops the newest excess workers.
128	func (s *WorkerSupervisor) Reconcile() (ReconcileResult, error) {
129		s.mu.Lock()
130		defer s.mu.Unlock()
131	
132		var result ReconcileResult
133	
134		desired, err := s.loadDesired()
135		if err != nil {
136			return result, err
137		}
138		recs, err := s.ctrl.List()
139		if err != nil {
140			return result, err
141		}
142		byID := make(map[string]WorkerRecord, len(recs))
143		for _, r := range recs {
144			byID[r.ID] = r
145		}
146		now := s.now()
147	
148		// Stale pass: a running/stopping disk record we do not manage and that has
149		// no live in-memory worker is reconciled to stopped. It is never adopted.
150		for _, r := range recs {
151			if _, ok := s.managed[r.ID]; ok {
152				continue
153			}
154			if (r.State == workerStateRunning || r.State == workerStateStopping) && !s.ctrl.HasLiveWorker(r.ID) {
155				if stopErr := s.ctrl.Stop(r.ID); stopErr == nil {
156					result.StaleMarked = append(result.StaleMarked, r.ID)
157				} else {
158					result.Errors = append(result.Errors, stopErr.Error())
159				}
160			}
161		}
162	
163		// Classify managed workers into healthy-running and crashed.
164		running := 0
165		for id := range s.managed {
166			r, ok := byID[id]
167			switch {
168			case !ok:
169				// The record vanished entirely — treat as an unexpected exit.
170				delete(s.managed, id)
171				s.pendingRestart++
172			case isTerminalWorkerState(r.State):
173				delete(s.managed, id)
174				if r.State == workerStateStopped {
175					// Operator-initiated stop — not a restart candidate.
176					continue
177				}
178				s.pendingRestart++
179			case !s.ctrl.HasLiveWorker(id):
180				// Disk says running but the goroutine is gone — crashed.
181				delete(s.managed, id)
182				s.pendingRestart++
183			default:
184				running++
185			}
186		}
187	
188		// Restart pass: replace crashed managed workers, gated by restart policy.
189		for s.pendingRestart > 0 && running < desired.DesiredCount {
190			ok, reason := s.restartAllowed(desired.Restart, now)
191			if !ok {
192				result.RestartSkipped = append(result.RestartSkipped, reason)
193				break
194			}
195			rec, startErr := s.startWorker(desired)
196			if startErr != nil {
197				result.Errors = append(result.Errors, startErr.Error())
198				break
199			}
200			s.restarts = append(s.restarts, now)
201			s.backoffUntil = now.Add(s.backoffDuration(desired.Restart))
202			s.pendingRestart--
203			running++
204			result.Restarted = append(result.Restarted, rec.ID)
205		}
206	
207		// Initial provisioning: only when no crashed slot is being held back by
208		// restart policy. These are first-time starts, not restarts, so they are
209		// not policy-gated.
210		if s.pendingRestart == 0 {
211			for running < desired.DesiredCount {
212				rec, startErr := s.startWorker(desired)
213				if startErr != nil {
214					result.Errors = append(result.Errors, startErr.Error())
215					break
216				}
217				running++
218				result.Started = append(result.Started, rec.ID)
219			}
220		}
221	
222		// Excess: stop the newest managed running workers down to desired_count.
223		if running > desired.DesiredCount {
224			excess := running - desired.DesiredCount
225			for _, id := range s.newestManagedIDs(excess) {
226				if stopErr := s.ctrl.Stop(id); stopErr == nil {
227					delete(s.managed, id)
228					result.Stopped = append(result.Stopped, id)
229				} else {
230					result.Errors = append(result.Errors, stopErr.Error())
231				}
232			}
233		}
234	
235		return result, nil
236	}
