238	// startWorker expands the default spec and starts a worker through the
239	// controller, recording it as managed.
240	func (s *WorkerSupervisor) startWorker(desired *WorkerDesiredState) (WorkerRecord, error) {
241		spec := desired.DefaultSpec.toExecuteLoopSpec(s.projectRoot)
242		rec, err := s.ctrl.StartExecuteLoop(spec)
243		if err != nil {
244			return WorkerRecord{}, err
245		}
246		s.managed[rec.ID] = managedWorker{spec: spec, startedAt: rec.StartedAt}
247		return rec, nil
248	}
