250	// restartAllowed reports whether a crashed managed worker may be restarted
251	// now under policy, returning a human-readable reason when it may not.
252	func (s *WorkerSupervisor) restartAllowed(policy WorkerRestartPolicy, now time.Time) (bool, string) {
253		if !policy.Enabled {
254			return false, "restart disabled"
255		}
256		if s.RestartPauseCheck != nil {
257			if paused, reason := s.RestartPauseCheck(); paused {
258				if reason == "" {
259					reason = "restart paused"
260				}
261				return false, reason
262			}
263		}
264		if now.Before(s.backoffUntil) {
265			return false, "within backoff window"
266		}
267		if policy.MaxRestartsPerHour > 0 && s.restartsInLastHour(now) >= policy.MaxRestartsPerHour {
268			return false, "max restarts per hour reached"
269		}
270		return true, ""
271	}
272	
273	func (s *WorkerSupervisor) restartsInLastHour(now time.Time) int {
274		cutoff := now.Add(-time.Hour)
275		n := 0
276		for _, t := range s.restarts {
277			if t.After(cutoff) {
278				n++
279			}
280		}
281		return n
282	}
283	
284	func (s *WorkerSupervisor) backoffDuration(policy WorkerRestartPolicy) time.Duration {
285		if policy.Backoff == "" {
286			return 0
287		}
288		d, err := time.ParseDuration(policy.Backoff)
289		if err != nil {
290			return 0
291		}
292		return d
293	}
