295	// newestManagedIDs returns up to n managed worker IDs ordered newest-first by
296	// start time.
297	func (s *WorkerSupervisor) newestManagedIDs(n int) []string {
298		ids := make([]string, 0, len(s.managed))
299		for id := range s.managed {
300			ids = append(ids, id)
301		}
302		sort.Slice(ids, func(i, j int) bool {
303			return s.managed[ids[i]].startedAt.After(s.managed[ids[j]].startedAt)
304		})
305		if n > len(ids) {
306			n = len(ids)
307		}
308		return ids[:n]
309	}
