 52	func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
 53		if a == nil || a.manager == nil {
 54			return nil, fmt.Errorf("worker dispatcher is not configured")
 55		}
 56		if err := ctx.Err(); err != nil {
 57			return nil, err
 58		}
 59		if kind != "work" {
 60			return nil, fmt.Errorf("unsupported worker kind %q", kind)
 61		}
 62	
 63		var spec executeloop.ExecuteLoopSpec
 64		if rawArgs != nil && *rawArgs != "" {
 65			if err := rejectLegacyExecuteLoopWorkerArgs([]byte(*rawArgs)); err != nil {
 66				return nil, err
 67			}
 68			if err := json.Unmarshal([]byte(*rawArgs), &spec); err != nil {
 69				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
 70			}
 71		}
 72	
 73		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
 74		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
 75		// for this project so the "+ Add worker" button can refuse cleanly.
 76		if wc := loadWorkersConfig(projectRoot); wc != nil {
 77			if defaultSpec := wc.DefaultSpec; defaultSpec != nil {
 78				if spec.Profile == "" {
 79					spec.Profile = defaultSpec.Profile
 80				}
 81				if spec.Effort == "" {
 82					spec.Effort = defaultSpec.Effort
 83				}
 84			}
 85			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
 86				running := a.countRunningDrainWorkers(projectRoot)
 87				if running >= *wc.MaxCount {
 88					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
 89				}
 90			}
 91		}
 92	
 93		// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
 94		// (no rawArgs, no workers.default_spec) must produce a spec with
 95		// Profile: "default" and nothing else. This eliminates the historical
 96		// 19-burn drain-queue failure mode where an empty spec fanned out into
 97		// per-powerClass ladder iteration with no upstream synthesis target.
 98		if spec.Profile == "" {
 99			spec.Profile = "default"
100		}
101	
102		workerSpec, err := prepareExecuteLoopWorkerSpec(projectRoot, spec, executeloop.ModeWatch)
103		if err != nil {
104			return nil, err
105		}
106		record, err := a.manager.StartExecuteLoop(workerSpec)
107		if err != nil {
108			return nil, err
109		}
110		return &ddxgraphql.WorkerDispatchResult{
111			ID:    record.ID,
112			State: record.State,
113			Kind:  record.Kind,
114		}, nil
115	}
