 56	async function mockGraphQL(
 57		page: import('@playwright/test').Page,
 58		workers: Record<string, unknown>[],
 59		options: { maxCount?: number | null; reportedWorkers?: Record<string, unknown>[] } = {}
 60	) {
 61		const desiredCalls: Array<Record<string, unknown>> = [];
 62		const restartCalls: Array<Record<string, unknown>> = [];
 63	
 64		await page.route('/api/projects', async (route) => {
 65			await route.fulfill({
 66				status: 200,
 67				contentType: 'application/json',
 68				body: JSON.stringify([PROJECT])
 69			});
 70		});
 71	
 72		await page.route('/graphql', async (route) => {
 73			const body = route.request().postDataJSON() as {
 74				query: string;
 75				variables?: Record<string, unknown>;
 76			};
 77	
 78			if (body.query.includes('NodeInfo')) {
 79				await route.fulfill({
 80					status: 200,
 81					contentType: 'application/json',
 82					body: JSON.stringify({ data: { nodeInfo: { id: NODE_ID, name: NODE_NAME } } })
 83				});
 84			} else if (body.query.includes('Projects')) {
 85				await route.fulfill({
 86					status: 200,
 87					contentType: 'application/json',
 88					body: JSON.stringify({
 89						data: { projects: { edges: [PROJECT].map((project) => ({ node: project })) } }
 90					})
 91				});
 92			} else if (
 93				body.query.includes('SetWorkerDesiredState') ||
 94				body.query.includes('setWorkerDesiredState')
 95			) {
 96				desiredCalls.push(body.variables ?? {});
 97				await route.fulfill({
 98					status: 200,
 99					contentType: 'application/json',
100					body: JSON.stringify({
101						data: {
102							setWorkerDesiredState: {
103								id: PROJECT_PATH,
104								state: `desired_count=${body.variables?.desiredCount}`,
105								kind: 'desired-state'
106							}
107						}
108					})
109				});
110			} else if (body.query.includes('RestartWorker') || body.query.includes('restartWorker')) {
111				restartCalls.push(body.variables ?? {});
112				await route.fulfill({
113					status: 200,
114					contentType: 'application/json',
115					body: JSON.stringify({
116						data: {
117							restartWorker: {
118								id: body.variables?.id,
119								state: 'running',
120								kind: 'work'
121							}
122						}
123					})
124				});
125			} else if (body.query.includes('WorkersByProject') || body.query.includes('workersByProject')) {
126				await route.fulfill({
127					status: 200,
128					contentType: 'application/json',
129					body: JSON.stringify({ data: makeWorkersResponse(workers, options.maxCount ?? null) })
130				});
131			} else if (
132				body.query.includes('QueueAndWorkersSummary') ||
133				body.query.includes('queueAndWorkersSummary')
134			) {
135				await route.fulfill({
136					status: 200,
137					contentType: 'application/json',
138					body: JSON.stringify({
139						data: {
140							queueAndWorkersSummary: {
141								readyBeads: 0,
142								runningWorkers: workers.filter((worker) => worker.state === 'running').length,
143								totalWorkers: workers.length,
144								maxCount: options.maxCount ?? null
145							}
146						}
147					})
148				});
149			} else if (
150				body.query.includes('ReportedWorkersByProject') ||
151				body.query.includes('reportedWorkers')
152			) {
153				await route.fulfill({
154					status: 200,
155					contentType: 'application/json',
156					body: JSON.stringify({ data: { reportedWorkers: options.reportedWorkers ?? [] } })
157				});
158			} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
159				await route.fulfill({
160					status: 200,
161					contentType: 'application/json',
162					body: JSON.stringify({ data: makeSessionsResponse() })
163				});
164			} else {
165				await route.continue();
166			}
167		});
168	
169		return { desiredCalls, restartCalls };
170	}
